const crypto = require('crypto');
const https = require('https');
const { URL } = require('url');

function httpsRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try { resolve({ statusCode: res.statusCode, body: JSON.parse(data) }); }
        catch { resolve({ statusCode: res.statusCode, body: data }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

function ghRequest(method, path, pat, body) {
  const url = new URL(`https://api.github.com${path}`);
  const opts = {
    hostname: url.hostname,
    path: url.pathname,
    method,
    headers: {
      'Authorization': `token ${pat}`,
      'Accept': 'application/vnd.github.v3+json',
      'User-Agent': 'n8n-stoa-factory'
    }
  };
  if (body) {
    const bodyStr = JSON.stringify(body);
    opts.headers['Content-Type'] = 'application/json';
    opts.headers['Content-Length'] = Buffer.byteLength(bodyStr);
    return httpsRequest(opts, bodyStr);
  }
  return httpsRequest(opts);
}

const pr = $input.first().json.query.pr;
const token = $input.first().json.query.token;
const repo = 'stoa-platform/stoa';
const prURL = `https://github.com/${repo}/pull/${pr}`;

// Validate params
if (!pr || !token) {
  return [{ json: { redirectURL: `https://github.com/${repo}` } }];
}

// Validate HMAC
const secret = $env.APPROVE_HMAC_SECRET;
if (!secret) {
  return [{ json: { redirectURL: `https://github.com/${repo}` } }];
}
const expected = crypto.createHmac('sha256', secret).update(pr).digest('hex');
if (token !== expected) {
  return [{ json: { redirectURL: `https://github.com/${repo}` } }];
}

const pat = $env.GITHUB_PAT;

try {
  // Fetch PR (get branch name)
  const prRes = await ghRequest('GET', `/repos/${repo}/pulls/${pr}`, pat);
  if (prRes.statusCode !== 200) {
    return [{ json: { redirectURL: prURL } }];
  }
  const branchRef = prRes.body.head && prRes.body.head.ref;

  // Squash merge
  const mergeRes = await ghRequest('PUT', `/repos/${repo}/pulls/${pr}/merge`, pat, { merge_method: 'squash' });

  // Delete branch (best-effort)
  if (branchRef) {
    try {
      await ghRequest('DELETE', `/repos/${repo}/git/refs/heads/${branchRef}`, pat);
    } catch (e) { /* ignore */ }
  }

  return [{ json: { redirectURL: prURL } }];
} catch (e) {
  return [{ json: { redirectURL: prURL } }];
}
